import json

# Load company names
with open(locals()['var_functions.execute_python:6'], 'r') as f:
    data = json.load(f)

company_names = data['company_names']

# Get company names for top 5
top_5_tickers = ['SES', 'FTFT', 'TGLS', 'TMSR', 'SNSS']

company_info = {}
for ticker in top_5_tickers:
    if ticker in company_names:
        company_info[ticker] = company_names[ticker]

print('__RESULT__:')
print(json.dumps({
    'top_5_companies_with_details': [
        {'ticker': 'SES', 'company_name': company_info.get('SES', 'Not found')},
        {'ticker': 'FTFT', 'company_name': company_info.get('FTFT', 'Not found')},
        {'ticker': 'TGLS', 'company_name': company_info.get('TGLS', 'Not found')},
        {'ticker': 'TMSR', 'company_name': company_info.get('TMSR', 'Not found')},
        {'ticker': 'SNSS', 'company_name': company_info.get('SNSS', 'Not found')}
    ]
}, indent=2))

